using System;

[AttributeUsage(AttributeTargets.All)]
public class CustomAttr : Attribute
{
    public CustomAttr(string desc) { Description = desc; }
    public string Description { get; }
}

[CustomAttr("type level")]
public interface IAccountService
{
    [CustomAttr("method level")]
    string GetAccount([CustomAttr("param level")] int id);
}

