#pragma warning disable CS1591, CS1573
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class AccountController : ControllerBase
    {
        private readonly global::IAccountService iAccountService;
        public AccountController(global::IAccountService iAccountService)
        {
            this.iAccountService = iAccountService;
        }

        [Route("GetAccount/{id}")]
        [HttpGet]
        public string GetAccount([FromRoute] int id)
        {
            return this.iAccountService.GetAccount(id);                    
        }
    }
}
